# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

from dataclasses import dataclass
from typing import List, Optional
import ariadne

# Define types
type_defs = """
    type Query {
        user(id: ID!): User
        users: [User]
    }
    
    type User {
        id: ID!
        username: String!
        bio: String
        email: String!
        phone: String
        address: String
        posts: [Post]
    }
    
    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }
"""
# Define data classes for user and post
@dataclass
class User:
    id: str
    username: str
    bio: Optional[str] = None
    email: Optional[str] = None
    phone: Optional[str] = None
    address: Optional[str] = None
    posts: Optional[List['Post']] = None
    
@dataclass
class Post:
    id: str
    title: str
    content: str
    author: User

# Dummy data for users and posts
users = [User(id="1", username="JohnDoe", bio="I am John Doe", email="john@example.com", phone="1234567890", address="123, Street"), User(id="2", username="JaneSmith", bio="I am Jane Smith", email="jane@example.com", phone="0987654321", address="456, Avenue")]
posts = [Post(id="1", title="Hello World", content="This is my first post", author=users[0]), Post(id="2", title="Second Post", content="I am writing a second post", author=users[1])]
users[0].posts = [posts[0]]
users[1].posts = [posts[1]]

# Define resolvers
resolvers = {
    'Query': {
        'user': lambda _, info, id: next((u for u in users if u.id == id), None),
        'users': lambda _: users
    },
    User: {
        'posts': lambda user, _: [post for post in posts if post.author == user]
    }
}

# Setup schema and middleware
schema = ariadne.Schema(type_defs, resolvers)
app = ariadne.FlaskApplication(schema=schema)

@app.middleware("graphql-request")
def resolve_current_user(resolver, obj, info, **kwargs):
    current_user = kwargs.get('current_user')
    if not current_user:
        raise Exception('Not authenticated!')
    return resolver(obj, info, current_user=current_user)
    
if __name__ == "__main__":
    app.run()